High firearm ownership rates and high homicide rates refer to firearm ownership rates above 50% and homicide rates above 10 per 100,000 people, respectively; 
These rates are often used in studies that explore the relationship between gun ownership and crime; 
Economic factors, unemployment rate, poverty rate, and GDP per capita are commonly used indicators to analyze the socioeconomic conditions of a country.

sql:
SELECT countries.country_name, mass_shootings.number_of_incidents, mass_shootings.year
FROM countries
INNER JOIN mass_shootings ON countries.country_id = mass_shootings.country_id;

SELECT c.country_name, fo.guns_per_100 as max_guns_per_100
FROM countries c
JOIN firearm_ownership fo ON c.country_id = fo.country_id
WHERE fo.guns_per_100 = (
    SELECT MAX(guns_per_100) FROM firearm_ownership
);

SELECT 
    (SELECT homicides_by_firearm FROM homicide_rates WHERE country_id = (SELECT country_id FROM countries ORDER BY gdp DESC LIMIT 1)) AS highest_gdp_homicides,
    (SELECT number_of_incidents FROM mass_shootings WHERE country_id = (SELECT country_id FROM countries ORDER BY population DESC LIMIT 1)) AS highest_population_mass_shootings;
